best = []
for h,text in hadith_texts:
    tokens = normalized_token_set(text)
    inter = len(orig_tokens & tokens)
    if inter == 0:
        continue
    # compute f1
    prec = inter/len(orig_tokens) if orig_tokens else 0
    rec = inter/len(tokens) if tokens else 0
    if prec+rec == 0:
        f1 = 0
    else:
